// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import java.util.Optional;

import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.UnaryTupleOperator;

/**
 * Greedy, bounded structural shrinking: repeatedly tries pair-preserving simplifications (unwrap matching unary roots,
 * drop VALUES rows in lockstep) and keeps a simplification only while the SAME invariant still fails. Bounded so a
 * pathological failure never stalls the run.
 */
final class PairShrinker {
	private static final int MAX_ATTEMPTS = 40;

	FuzzViolation shrink(FuzzViolation violation, FuzzProfile profile, DifferentialOracle oracle) {
		FuzzViolation best = violation;
		int attempts = 0;
		boolean progress = true;
		while (progress && attempts < MAX_ATTEMPTS) {
			progress = false;
			for (TreePair candidate : simplifications(best.pair())) {
				attempts++;
				Optional<FuzzViolation> replayed = replay(candidate, profile, oracle, best.invariant());
				if (replayed.isPresent()) {
					best = replayed.get();
					progress = true;
					break;
				}
				if (attempts >= MAX_ATTEMPTS) {
					break;
				}
			}
		}
		return best;
	}

	private Optional<FuzzViolation> replay(TreePair pair, FuzzProfile profile, DifferentialOracle oracle,
			FuzzInvariant invariant) {
		try {
			for (FuzzViolation violation : oracle.judge(pair, profile)) {
				if (violation.invariant() == invariant) {
					return Optional.of(violation);
				}
			}
		} catch (Throwable ignored) {
			// A crashing simplification is not a valid shrink step.
		}
		return Optional.empty();
	}

	private List<TreePair> simplifications(TreePair pair) {
		List<TreePair> result = new ArrayList<>();
		unwrapRoots(pair).ifPresent(result::add);
		dropValuesRow(pair).ifPresent(result::add);
		return result;
	}

	private Optional<TreePair> unwrapRoots(TreePair pair) {
		TupleExpr original = pair.original();
		TupleExpr candidate = pair.candidate();
		if (original instanceof QueryRoot originalRoot && candidate instanceof QueryRoot candidateRoot) {
			return Optional.of(shrunk(pair, originalRoot.getArg().clone(), candidateRoot.getArg().clone()));
		}
		if (original instanceof UnaryTupleOperator originalUnary
				&& candidate instanceof UnaryTupleOperator candidateUnary
				&& original.getClass() == candidate.getClass()) {
			return Optional.of(shrunk(pair, originalUnary.getArg().clone(), candidateUnary.getArg().clone()));
		}
		return Optional.empty();
	}

	private Optional<TreePair> dropValuesRow(TreePair pair) {
		TupleExpr original = pair.original().clone();
		TupleExpr candidate = pair.candidate().clone();
		boolean dropped = dropFirstRow(original) && dropFirstRow(candidate);
		if (!dropped) {
			return Optional.empty();
		}
		return Optional.of(shrunk(pair, original, candidate));
	}

	private boolean dropFirstRow(TupleExpr tree) {
		for (BindingSetAssignment assignment : MutatorLibrary.collect(tree, BindingSetAssignment.class)) {
			if (assignment.getBindingSets()instanceof Collection<?> rows && rows.size() >= 2) {
				List<BindingSet> remaining = new ArrayList<>();
				boolean first = true;
				for (Object row : rows) {
					if (first) {
						first = false;
						continue;
					}
					remaining.add((BindingSet) row);
				}
				assignment.setBindingSets(remaining);
				return true;
			}
		}
		return false;
	}

	private TreePair shrunk(TreePair pair, TupleExpr original, TupleExpr candidate) {
		return new TreePair(pair.label() + "+shrunk", pair.sourceId(), pair.seed(), pair.mutatorChain(),
				original, candidate, pair.expectation());
	}
}
